    let json = r#"{
        "mode": "all",
        "scope": "session",
        "workspace_mount": "rw",
        "no_network": true,
        "resource_limits": {"memory_limit": "1G"}
    }"#;
    let config: SandboxConfig = serde_json::from_str(json).unwrap();
    assert_eq!(config.mode, SandboxMode::All);
    assert_eq!(config.workspace_mount, WorkspaceMount::Rw);
